const { GoogleGenAI } = require('@google/genai');
const { createClient } = require('@supabase/supabase-js');

async function runTest() {
    const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);
    // Switching to the 'Consumer' model string from the demo repo
    const MODEL_ID = 'gemini-live-2.5-flash-preview';

    console.log("--- [STEP 1] Downloading audio.pcm ---");
    const { data: audioBlob } = await supabase.storage.from('Audio').download('audio.pcm');
    const audioBuffer = Buffer.from(await audioBlob.arrayBuffer());
    console.log(`--- [INFO] Audio Loaded: ${audioBuffer.length} bytes ---`);

    const genAI = new GoogleGenAI(process.env.GEMINI_API_KEY);

    const session = await genAI.live.connect({
        model: MODEL_ID,
        config: {
            responseModalities: ['AUDIO'],
            outputAudioTranscription: {},
            inputAudioTranscription: {},
            systemInstruction: { parts: [{ text: "You are a transcription expert. Repeat exactly what you hear in the audio stream." }] }
        },
        callbacks: {
            onmessage: (message) => {
                if (message.serverContent?.inputAudioTranscription?.text) {
                  console.log("--- [AI HEARD USER] ---", message.serverContent.inputAudioTranscription.text);
                }
                if (message.serverContent?.modelTurn) {
                    const textPart = message.serverContent.modelTurn.parts.find(p => p.text);
                    if (textPart) console.log("--- [AI REPLY] ---", textPart.text);
                }
            },
            onerror: (err) => { console.error("--- [SDK ERROR] ---", err); process.exit(1); }
        }
    });

    // 1. PRIME THE SESSION
    console.log("--- [STEP 2] Priming Session... ---");
    session.sendClientContent({ turns: [{ role: 'user', parts: [{ text: "I am starting the audio stream now. Listen carefully." }] }], turnComplete: true });
    await new Promise(r => setTimeout(r, 2000));

    // 2. DRIP FEED USING REPO SYNTAX
    console.log("--- [STEP 3] Drip-feeding using Media Object syntax... ---");
    const CHUNK_SIZE = 1024;
    for (let i = 0; i < audioBuffer.length; i += CHUNK_SIZE) {
        const chunk = audioBuffer.slice(i, i + CHUNK_SIZE);

        // MATCHING REPO SYNTAX: sendRealtimeInput({ media: { ... } })
        session.sendRealtimeInput({
            media: {
                data: chunk.toString('base64'),
                mimeType: 'audio/pcm;rate=16000'
            }
        });

        await new Promise(r => setTimeout(r, 15));
        if (i % (CHUNK_SIZE * 100) === 0) console.log(`--- [INFO] Streaming: ${i}/${audioBuffer.length} ---`);
    }

    // 3. THE REQUEST
    console.log("--- [STEP 4] Audio finished. Asking for transcription... ---");
    session.sendClientContent({
        turns: [{ role: 'user', parts: [{ text: "Please transcribe everything I just said in the audio stream." }] }],
        turnComplete: true
    });

    setTimeout(() => { console.log("--- [FINISH] Closing test session. ---"); process.exit(0); }, 20000);
}

runTest().catch(err => { console.error(err); process.exit(1); });

