            await new Promise(r => setTimeout(r, 20)); // Flow pace
        }
    }

    console.log("--- [STEP 3] Stream Finished. Closing Turn... ---");

    // 4. SIGNAL TURN COMPLETE
    // This is the only place we use sendClientContent in the whole flow
