        turns: [{ role: 'user', parts: [{ text: "I am done sending data. Please provide the analysis now." }] }],
        turnComplete: true
    });

    // Final wait for response
    setTimeout(() => { console.log("--- [TIMEOUT] ---"); process.exit(0); }, 20000);
}

runTest().catch(console.error);

